  const db = new Kysely({
    dialect: new MysqlDialect({ pool })
  });

  t.after(async () => {
    await db.destroy();
  });

  await runMigrations(db);
  return db;
}

async function createServer(t, objectStorageConfig) {
  const restoreEnv = withTestDatabaseEnv(objectStorageConfig);
  const app = createExportPlatformServer();

  t.after(async () => {
    restoreEnv();
    await app.close();
  });

  return app;
}

