 163: function resolveTotalCount(input: {
 164:   task: ExportTaskRecord;
 165:   checkpoint: CheckpointRecord | undefined;
 166:   events: TaskEventRecord[];
 167: }): number {
 168:   const eventTotal = input.events.reduce<number | null>((current, event) => {
 169:     const checkpoint = parseJsonRecord(event.batchCheckpoint);
 170:     const totalCount = readNonNegativeInteger(checkpoint?.totalCount);
 171:     if (totalCount !== null) {
 172:       return current === null ? totalCount : Math.max(current, totalCount);
 173:     }
 174:     return current;
 175:   }, null);
 176: 
 177:   if (eventTotal !== null) {
 178:     return eventTotal;
 179:   }
 180: 
 181:   if (input.task.status === "COMPLETED") {
 182:     return input.checkpoint?.processedCount ?? 0;
 183:   }
 184: 
 185:   return 0;
 186: }
