 188: function resolveProcessedCount(input: {
 189:   task: ExportTaskRecord;
 190:   checkpoint: CheckpointRecord | undefined;
 191:   totalCount: number;
 192: }): number {
 193:   const checkpointCount = input.checkpoint?.processedCount ?? 0;
 194:   if (input.totalCount > 0) {
 195:     return Math.min(checkpointCount, input.totalCount);
 196:   }
 197: 
 198:   if (input.task.status === "COMPLETED" && checkpointCount === 0) {
 199:     return input.totalCount;
 200:   }
 201: 
 202:   return checkpointCount;
 203: }
