 221: function resolveTaskFailure(
 222:   audits: AuditLogRecord[],
 223:   events: TaskEventRecord[]
 224: ): {
 225:   errorCode: string | null;
 226:   errorMessage: string | null;
 227: } {
 228:   const auditFailures = audits
 229:     .filter((audit) => audit.result === "FAILED" && audit.errorCode !== "SUCCESS")
 230:     .map((audit) => ({
 231:       occurredAt: audit.occurredAt,
 232:       errorCode: audit.errorCode,
 233:       errorMessage: responseCodeMessage(audit.errorCode)
 234:     }));
 235: 
 236:   const eventFailures = events.flatMap((event) => {
 237:     const checkpoint = parseJsonRecord(event.batchCheckpoint);
 238:     const errorCode = readNonEmptyString(checkpoint?.errorCode);
 239:     if (!errorCode || errorCode === "SUCCESS") {
 240:       return [];
 241:     }
 242: 
 243:     return [
 244:       {
 245:         occurredAt: event.occurredAt,
 246:         errorCode,
 247:         errorMessage: readNonEmptyString(checkpoint?.errorMessage) ?? responseCodeMessage(errorCode)
 248:       }
 249:     ];
 250:   });
 251: 
 252:   const failedRecord = [...auditFailures, ...eventFailures].sort(
 253:     (left, right) => right.occurredAt.getTime() - left.occurredAt.getTime()
 254:   )[0];
 255: 
 256:   if (!failedRecord) {
 257:     return {
 258:       errorCode: null,
 259:       errorMessage: null
 260:     };
 261:   }
 262: 
 263:   return {
 264:     errorCode: failedRecord.errorCode,
 265:     errorMessage: failedRecord.errorMessage
 266:   };
 267: }
